SELECT member_name, member_role
FROM project_members
WHERE project = (SELECT unics_id FROM projects WHERE acronym = 'GTBB');

SELECT title FROM projects
JOIN project_subject_areas ON projects.unics_id = project_subject_areas.project
WHERE title LIKE '%Climate change%' AND title LIKE '%Carbon cycle%';

SELECT DISTINCT projects.acronym
FROM projects
WHERE start_year = 2018;

SELECT i.institutions_name
FROM institutions i
JOIN countries c ON i.country_id = c.unics_id;

SELECT DISTINCT countries.country_name
FROM countries
JOIN institutions ON countries.unics_id = institutions.country_id;

